#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int numbers[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &numbers[i]);
        }
        int x, m;
        scanf("%d %d", &x, &m);
        int max_xor = -1;
        for (int i = 0; i < N; i++) {
            if (numbers[i] <= m) {
                max_xor = (max_xor == -1) ? (x ^ numbers[i]) : ((x ^ numbers[i]) > max_xor) ? (x ^ numbers[i]) : max_xor;
            }
        }
        printf("%d\n", max_xor);
    }
    return 0;
}

