        while (T-- > 0) {
            int N = sc.nextInt();
            int[] numbers = new int[N];
            for (int i = 0; i < N; i++) {
                numbers[i] = sc.nextInt();
            }
            int x = sc.nextInt();
            int m = sc.nextInt();
            int max_xor = -1;
            for (int i = 0; i < N; i++) {
                if (numbers[i] <= m) {
                    max_xor = (max_xor == -1) ? (x ^ numbers[i]) : ((x ^ numbers[i]) > max_xor) ? (x ^ numbers[i]) : max_xor;
                }
            }
            System.out.println(max_xor);
        }
    }
}

