const lines = require('fs').readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const N = parseInt(readline());
    const numbers = readline().split(' ').map(Number);
    const [x, m] = readline().split(' ').map(Number);
    let max_xor = -1;
    for (let j = 0; j < N; j++) {
        if (numbers[j] <= m) {
            max_xor = (max_xor === -1) ? (x ^ numbers[j]) : Math.max(max_xor, x ^ numbers[j]);
        }
    }
    console.log(max_xor);
}
